            "timeout": 60,
            "statusMessage": "phase4 tool gate"
          }
        ]
      },
      {
        "matcher": "Subagent|Task|Agent",
        "hooks": [
          {
            "type": "command",
            "command": "node \"${CLAUDE_PROJECT_DIR}/.claude/hooks/phase2-planning-gate.mjs\"",
            "timeout": 60,
            "statusMessage": "phase2 planning gate"
          },
          {
            "type": "command",
            "command": "node \"${CLAUDE_PROJECT_DIR}/.claude/hooks/phase3-subagent-gate.mjs\"",
            "timeout": 60,
            "statusMessage": "phase3 subagent gate"
          },
          {
            "type": "command",
            "command": "node \"${CLAUDE_PROJECT_DIR}/.claude/hooks/phase3-task-running-update.mjs\"",
            "timeout": 60,
            "statusMessage": "phase3 task running update"
          },
          {
            "type": "command",
            "command": "node \"${CLAUDE_PROJECT_DIR}/.claude/hooks/phase4-tool-gate.mjs\"",
            "timeout": 60,
            "statusMessage": "phase4 tool gate"
          }
        ]
      }
    ],
    "PostToolUse": [
      {
        "matcher": "Skill",
        "hooks": [
          {
            "type": "command",
            "command": "node \"${CLAUDE_PROJECT_DIR}/.claude/hooks/phase1-status-shape-ensure.mjs\"",
            "timeout": 60,
            "statusMessage": "phase1 status shape ensure"
          }
        ]
      },
      {
        "matcher": "Subagent|Task|Agent",
        "hooks": [
          {
            "type": "command",
            "command": "node \"${CLAUDE_PROJECT_DIR}/.claude/hooks/phase2-planning-complete.mjs\"",
            "timeout": 120,
            "statusMessage": "phase2 planning complete"
          },
          {
            "type": "command",
            "command": "node \"${CLAUDE_PROJECT_DIR}/.claude/hooks/phase3-review-complete.mjs\"",
            "timeout": 600,
            "statusMessage": "phase3 review complete"
          },
          {
            "type": "command",
            "command": "node \"${CLAUDE_PROJECT_DIR}/.claude/hooks/phase3-metrics-report.mjs\"",
            "timeout": 600,
            "statusMessage": "phase3 metrics report"
          }
        ]
      },
      {
        "matcher": "*",
        "hooks": [
          {
            "type": "command",
            "command": "node \"${CLAUDE_PROJECT_DIR}/.claude/hooks/tool-healthcheck.mjs\"",
            "timeout": 60,
            "statusMessage": "tool healthcheck"
          }
        ]
      }
    ],
    "Stop": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "node \"${CLAUDE_PROJECT_DIR}/.claude/hooks/phase1-init-complete.mjs\"",
            "timeout": 60,
            "statusMessage": "phase1 init complete"
          },
          {
            "type": "command",
            "command": "node \"${CLAUDE_PROJECT_DIR}/.claude/hooks/phase4-summary-complete.mjs\"",
            "timeout": 120,
            "statusMessage": "phase4 summary complete and deliver"
          }
        ]
      }
    ]
  }
}

